import type { CardConfig } from "../contracts/types";

export function migrateSavedConfigSensorLegacy(config: CardConfig): boolean {
  if (config.type === "local_sensor") {
    config.type = "sensor";
    config.sensor = "local";
    config.icon_on = "Auto";
    config.options = "";
    return true;
  }
  if (config.type === "text_sensor") {
    config.type = "sensor";
    config.entity = "";
    config.label = "";
    config.unit = "";
    config.precision = "text";
    config.icon_on = "Auto";
    return true;
  }
  return false;
}
